import { McpAgent } from "agents/mcp";
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import * as cheerio from "cheerio";
import REGULATIONS_INDEX from "../../data/regulations.json";

// ─── Types ───────────────────────────────────────────────────────────

interface RegulationEntry {
  id: number;
  name: string;
  allVersions: number[];
  isLatest: boolean;
}

interface Chapter {
  title: string;
  articles: Article[];
}

interface Article {
  title: string;
  content: string[];
}

interface RegulationContent {
  name: string;
  chapters: Chapter[];
  supplementary: string[];
}

// ─── Index (static, from bundled JSON) ───────────────────────────────

const regulations: RegulationEntry[] = REGULATIONS_INDEX.regulations;

function searchRegulations(query: string): RegulationEntry[] {
  const q = query.toLowerCase().replace(/\s+/g, "");
  return regulations.filter((r) =>
    r.name.toLowerCase().replace(/\s+/g, "").includes(q),
  );
}

function listRegulations(latestOnly: boolean): RegulationEntry[] {
  if (latestOnly) {
    return regulations.filter((r) => r.isLatest);
  }
  return regulations;
}

// ─── Fetcher ─────────────────────────────────────────────────────────

const BASE_URL =
  "https://rule.hansung.ac.kr/lmxsrv/law/lawFullContent.do";

async function fetchRegulationHtml(
  seqHistory: number,
): Promise<string | null> {
  const url = `${BASE_URL}?SEQ_HISTORY=${seqHistory}`;
  const res = await fetch(url, {
    headers: {
      "User-Agent": "hansung-regulation-mcp/0.1.0",
      Accept: "text/html",
    },
  });
  if (!res.ok) return null;
  const html = await res.text();
  if (!html.includes('class="lawname"')) return null;
  return html;
}

// ─── Parser ──────────────────────────────────────────────────────────

function parseRegulation(html: string): RegulationContent {
  const $ = cheerio.load(html);
  const name =
    $("div.lawname").first().text().trim().replace(/\s+/g, " ") || "Unknown";

  const result: RegulationContent = { name, chapters: [], supplementary: [] };
  let curChapter: Chapter = { title: "총칙", articles: [] };
  let curArticle: Article | null = null;
  let inSupplementary = false;

  $(
    "div.chapter, table caption, td, div.none, div.hang, div.ho, div.buTitle",
  ).each((_, el) => {
    const $el = $(el);
    const tagName = (el as any).tagName as string;
    const classes = $el.attr("class") || "";

    if (classes.includes("chapter")) {
      if (curArticle) {
        curChapter.articles.push(curArticle);
        curArticle = null;
      }
      if (curChapter.articles.length > 0 || curChapter.title) {
        result.chapters.push(curChapter);
      }
      curChapter = {
        title: $el.text().trim().replace(/\s+/g, " "),
        articles: [],
      };
      inSupplementary = false;
      return;
    }

    if (classes.includes("buTitle")) {
      if (curArticle) {
        curChapter.articles.push(curArticle);
        curArticle = null;
      }
      if (curChapter.articles.length > 0 || curChapter.title) {
        result.chapters.push(curChapter);
      }
      curChapter = {
        title: $el.text().trim().replace(/\s+/g, " "),
        articles: [],
      };
      inSupplementary = true;
      return;
    }

    if (tagName === "td") {
      const text = $el.text().trim();
      if (/제\s*\d+\s*조/.test(text) || /제\s*\d+\s*조의\d+/.test(text)) {
        if (curArticle) {
          curChapter.articles.push(curArticle);
        }
        curArticle = {
          title: text.replace(/\s+/g, " ").trim(),
          content: [],
        };
      }
      return;
    }

    if (
      classes.includes("none") ||
      classes.includes("hang") ||
      classes.includes("ho")
    ) {
      const text = $el
        .find("span")
        .map((_, span) => $(span).text().trim())
        .get()
        .join("");
      if (!text) return;
      const level = classes.includes("ho")
        ? 2
        : classes.includes("hang")
          ? 1
          : 0;
      const indent = "  ".repeat(level);
      const formatted = `${indent}${text}`;
      if (inSupplementary) {
        result.supplementary.push(formatted);
      } else if (curArticle) {
        curArticle.content.push(formatted);
      }
    }
  });

  if (curArticle) curChapter.articles.push(curArticle);
  if (curChapter.articles.length > 0 || curChapter.title) {
    result.chapters.push(curChapter);
  }

  return result;
}

function toMarkdown(reg: RegulationContent): string {
  const lines: string[] = [];
  lines.push(`# ${reg.name}`, "");
  for (const chapter of reg.chapters) {
    if (chapter.title) lines.push(`## ${chapter.title}`, "");
    for (const article of chapter.articles) {
      lines.push(`### ${article.title}`, "");
      for (const c of article.content) lines.push(c);
      lines.push("");
    }
  }
  if (reg.supplementary.length > 0) {
    lines.push("## 부칙", "");
    for (const s of reg.supplementary) lines.push(s);
    lines.push("");
  }
  return lines.join("\n");
}

function findArticle(
  reg: RegulationContent,
  articleQuery: string,
): Article | null {
  const numMatch = articleQuery.match(/(\d+)/);
  if (!numMatch) return null;
  const articleNum = numMatch[1];
  for (const chapter of reg.chapters) {
    for (const article of chapter.articles) {
      const titleNumMatch = article.title.match(/제\s*(\d+)\s*조/);
      if (titleNumMatch && titleNumMatch[1] === articleNum) {
        return article;
      }
    }
  }
  return null;
}

// ─── MCP Agent ───────────────────────────────────────────────────────

type Env = {
  MCP_OBJECT: DurableObjectNamespace;
};

export class HansungRegulationMCP extends McpAgent<Env> {
  server = new McpServer({
    name: "hansung-university-regulation-mcp",
    version: "0.1.0",
  });

  async init() {
    // Tool 1: search_regulations
    this.server.tool(
      "search_regulations",
      "한성대학교 규정을 키워드로 검색합니다. 규정명에서 키워드를 찾아 매칭되는 규정 목록을 반환합니다.",
      { query: z.string().describe("검색 키워드 (예: '학칙', '장학금', '교원임용')") },
      async ({ query }) => {
        const results = searchRegulations(query);
        if (results.length === 0) {
          return {
            content: [{ type: "text", text: `"${query}"에 대한 검색 결과가 없습니다.` }],
          };
        }
        const lines = results.map(
          (r) => `- [SEQ_HISTORY=${r.id}] ${r.name} (버전 ${r.allVersions.length}개)`,
        );
        return {
          content: [{
            type: "text",
            text: `"${query}" 검색 결과 (${results.length}건):\n\n${lines.join("\n")}\n\n규정 내용을 보려면 get_regulation 도구에 id를 전달하세요.`,
          }],
        };
      },
    );

    // Tool 2: list_regulations
    this.server.tool(
      "list_regulations",
      "한성대학교 규정 전체 목록을 반환합니다. 기본적으로 최신 버전만 표시하며, includeOldVersions=true로 구버전도 포함할 수 있습니다.",
      {
        includeOldVersions: z.boolean().optional().default(false)
          .describe("true이면 구버전 포함, false이면 최신 버전만 표시"),
      },
      async ({ includeOldVersions }) => {
        const results = listRegulations(!includeOldVersions);
        const lines = results.map((r) => `- [${r.id}] ${r.name}`);
        return {
          content: [{
            type: "text",
            text: `한성대학교 규정 목록 (${results.length}건):\n\n${lines.join("\n")}\n\n규정 내용을 보려면 get_regulation 도구에 id를 전달하세요.`,
          }],
        };
      },
    );

    // Tool 3: get_regulation
    this.server.tool(
      "get_regulation",
      "특정 규정의 전문을 조회합니다. search_regulations 또는 list_regulations에서 얻은 id(SEQ_HISTORY)를 사용하세요.",
      {
        id: z.number().int().positive()
          .describe("규정의 SEQ_HISTORY ID (search_regulations 또는 list_regulations 결과에서 확인)"),
      },
      async ({ id }) => {
        const html = await fetchRegulationHtml(id);
        if (!html) {
          return {
            content: [{ type: "text", text: `SEQ_HISTORY=${id}에 해당하는 규정을 찾을 수 없습니다.` }],
            isError: true,
          };
        }
        const parsed = parseRegulation(html);
        const markdown = toMarkdown(parsed);
        return { content: [{ type: "text", text: markdown }] };
      },
    );

    // Tool 4: get_regulation_article
    this.server.tool(
      "get_regulation_article",
      "특정 규정의 특정 조항만 조회합니다. 규정 id와 조항 번호(예: '제5조')를 입력하세요.",
      {
        id: z.number().int().positive().describe("규정의 SEQ_HISTORY ID"),
        article: z.string().describe("조항 번호 (예: '제5조', '5', '제12조')"),
      },
      async ({ id, article }) => {
        const html = await fetchRegulationHtml(id);
        if (!html) {
          return {
            content: [{ type: "text", text: `SEQ_HISTORY=${id}에 해당하는 규정을 찾을 수 없습니다.` }],
            isError: true,
          };
        }
        const parsed = parseRegulation(html);
        const found = findArticle(parsed, article);
        if (!found) {
          return {
            content: [{
              type: "text",
              text: `"${parsed.name}"에서 "${article}"에 해당하는 조항을 찾을 수 없습니다.\n\n사용 가능한 조항:\n${parsed.chapters
                .flatMap((c) => c.articles.map((a) => `- ${a.title}`))
                .join("\n")}`,
            }],
            isError: true,
          };
        }
        const contentText = found.content.join("\n");
        return {
          content: [{ type: "text", text: `# ${parsed.name}\n\n## ${found.title}\n\n${contentText}` }],
        };
      },
    );
  }
}

// ─── Export Worker handler ────────────────────────────────────────────

export default HansungRegulationMCP.serve("/mcp");
